pub const fn new(val: $int) -> Option<Self> {
    #[allow(non_contiguous_range_endpoints)]
    if let $pat = val {
        // SAFETY: just checked that the value matches the pattern
        Some(unsafe { $name(crate::mem::transmute(val)) })
    } else {
        None
    }
}

